import psycopg2
from flask import Flask, request, jsonify

app = Flask(__name__)

# Define a function to connect to the database
def connect_to_db():
    conn = psycopg2.connect(
        host="localhost",
        dbname="mydatabase",
        user="myuser",
        password="mypassword"
    )
    return conn

# Define a function to execute SQL queries
def execute_query(conn, query):
    cur = conn.cursor()
    cur.execute(query)
    rows = cur.fetchall()
    cur.close()
    return rows

# Define a function to build dynamic SQL queries based on user input
def build_query(table_name, column_names, filter_conditions):
    query = "SELECT " + ", ".join(column_names) + " FROM " + table_name
    if len(filter_conditions) > 0:
        query += " WHERE " + " AND ".join(filter_conditions)
    return query

# Define a function to handle API requests
@app.route("/api/v1/data", methods=["GET"])
def get_data():
    # Get the table name, column names, and filter conditions from the request
    table_name = request.args.get("table")
    column_names = request.args.getlist("columns[]")
    filter_conditions = request.args.getlist("filters[]")

    # Connect to the database and execute the SQL query
    conn = connect_to_db()
    query = build_query(table_name, column_names, filter_conditions)
    rows = execute_query(conn, query)

    # Return the results as JSON
    return jsonify(rows)